import os; open("circuits/IdentityProof.circom","w",encoding="utf-8",newline="\n").write("pragma circom 2.0.0;\n\ninclude \"../node_modules/circomlib/circuits/poseidon.circom\";\ninclude \"../node_modules/circomlib/circuits/comparators.circom\";\n\ntemplate IdentityProof() {\n    signal input secret;\n    signal input salt;\n    signal input commitment;\n    signal output identity_hash;\n    signal output verified;\n\n    component hasher = Poseidon(2);\n    hasher.inputs[0] <== secret;\n    hasher.inputs[1] <== salt;\n    identity_hash <== hasher.out;\n\n    component eq = IsEqual();\n    eq.in[0] <== identity_hash;\n    eq.in[1] <== commitment;\n    verified <== eq.out;\n}\n\ncomponent main {public [commitment]} = IdentityProof();\n"); print("Written")
